// Syntax: for (initialize; condition; increment) { code }

for (let i = 0; i < 5; i++) {
  console.log(i);
}
// Prints: 0, 1, 2, 3, 4

// Another example: count from 1 to 10
for (let count = 1; count <= 10; count++) {
  console.log(`Count: ${count}`);
}

let count = 0;

while (count < 5) {
  console.log(count);
  count++;
}
// Prints: 0, 1, 2, 3, 4

// Another example: keep asking until user says yes
let response = "no";
while (response !== "yes") {
  response = prompt("Do you want to continue?");
}

// Using break
for (let i = 0; i < 10; i++) {
  if (i === 5) {
    break; // Exit the loop
  }
  console.log(i);
}
// Prints: 0, 1, 2, 3, 4

// Using continue
for (let i = 0; i < 5; i++) {
  if (i === 2) {
    continue; // Skip this iteration
  }
  console.log(i);
}
// Prints: 0, 1, 3, 4

let fruits = ["apple", "banana", "cherry"];

for (let fruit of fruits) {
  console.log(fruit);
}
// Prints: apple, banana, cherry
